PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>

SELECT ?country ?medal WHERE {
  ?medal wdt:P31/wdt:P279* wd:Q1788716 .
  ?medal wdt:P17 ?country .
  ?medal wdt:P1455 ?precedence .
  FILTER (REGEX(?precedence, '^[0-9]+$'))
  BIND(xsd:integer(?precedence) AS ?prec_int)
  {
    SELECT ?country (MIN(?prec_int) AS ?min_prec) WHERE {
      ?medal wdt:P31/wdt:P279* wd:Q1788716 .
      ?medal wdt:P17 ?country .
      ?medal wdt:P1455 ?precedence .
      FILTER (REGEX(?precedence, '^[0-9]+$'))
      BIND(xsd:integer(?precedence) AS ?prec_int)
    }
    GROUP BY ?country
  }
  FILTER (?prec_int = ?min_prec)
  SERVICE wikibase:label { bd:serviceParam wikibase:language "en" }
}
LIMIT 10

PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>

SELECT ?country ?medal WHERE {
  ?medal wdt:P31/wdt:P279* wd:Q1788716 .
  ?medal wdt:P17 ?country .
  OPTIONAL { ?medal wdt:P1455 ?precedence }
  {
    SELECT ?country (MIN(?precedence) AS ?min_prec) WHERE {
      ?medal wdt:P31/wdt:P279* wd:Q1788716 .
      ?medal wdt:P17 ?country .
      OPTIONAL { ?medal wdt:P1455 ?precedence }
    }
    GROUP BY ?country
  }
  FILTER (BOUND(?precedence) && ?precedence = ?min_prec)
}
LIMIT 10
